use anyhow::Result;
use camino::Utf8PathBuf;
use chrono::Utc;
use clap::Parser;
use semver::Version;
use tufaceous::edit::RepositoryEditor;

use crate::sign::SignOptions;

#[derive(Debug, Parser)]
pub struct Args {
    /// Artifacts to add to the repository
    ///
    /// For OS images, use the directory generated by helios-build that contains
    /// zfs.img, gimlet.rom, etc.
    artifacts: Vec<Utf8PathBuf>,
    /// Add a standard set of fake artifacts
    #[clap(long)]
    fake: bool,
    /// Do not generate an Installinator document
    #[clap(long)]
    no_installinator_document: bool,
    /// ZIP archive output path
    #[clap(short = 'o', long)]
    output: Utf8PathBuf,
    #[clap(flatten)]
    sign_options: SignOptions,
    /// The system version (required)
    #[clap(short = 'V', long)]
    system_version: Version,
}

impl Args {
    pub async fn run(self) -> Result<()> {
        let mut editor = if self.fake {
            RepositoryEditor::fake(self.system_version)
        } else {
            RepositoryEditor::new(self.system_version)
        }?;
        editor = editor.set_generate_installinator_document(
            !self.no_installinator_document,
        );
        for path in self.artifacts {
            editor = editor.guess_artifact(path).await?;
        }
        let unsigned = editor.finish().await?;
        self.sign_options
            .sign(unsigned)
            .await?
            .write_zip_file(self.output, Utc::now())
            .await?;
        Ok(())
    }
}
